import type { QRData } from '../types/qr';
import { useParams } from 'react-router-dom';
import { useSubmitForm } from '../hooks/useForms';
import { clsx, type ClassValue } from 'clsx';
import { twMerge } from 'tailwind-merge';
import { downloadFile, getDownloadUrl } from '../utils/upload';
import { DEMO_DATA } from '../constants/demoData';

function cn(...inputs: ClassValue[]) { return twMerge(clsx(inputs)); }

interface DynamicViewProps {
  data: QRData;
  isWizardPreview?: boolean;
}

const DynamicView: React.FC<DynamicViewProps> = ({ data: initialData, isWizardPreview }) => {
  const { id: shortId } = useParams<{ id: string }>();

  // Merge with demo data if in wizard preview
  const data = React.useMemo(() => {
    if (!isWizardPreview) return initialData;

    const demo = DEMO_DATA[initialData.type] || {};

    // Helper to merge objects while prioritizing initialData but falling back to demo for empty values
    const mergeWithFallback = (target: any, source: any) => {
      if (!source) return target;
      if (!target) return source;

      const result = { ...source, ...target };

      Object.keys(source).forEach(key => {
        if (typeof source[key] === 'object' && source[key] !== null && !Array.isArray(source[key])) {
          result[key] = mergeWithFallback(target[key], source[key]);
        } else if (!target[key] || (Array.isArray(target[key]) && target[key].length === 0)) {
          result[key] = source[key];
        }
      });

      return result;
    };

    return mergeWithFallback(initialData, demo) as QRData;
  }, [initialData, isWizardPreview]);

  const submitMutation = useSubmitForm(shortId || '');

const [selectedType, setSelectedType] = useState<string | null>(null);
const [hoveredType, setHoveredType] = useState<string | null>(null);
const [config, setConfig] = useState<QRConfiguration>(INITIAL_CONFIG);

{qrTypes.map(type => (
   <button
     key={type.id}
     onMouseEnter={() => setHoveredType(type.id)}
     onMouseLeave={() => setHoveredType(null)}
     onClick={() => setSelectedType(type.id)}
     className={cn(
       "flex flex-col items-center text-center p-6 rounded-[2rem] border-2 transition-all hover:scale-[1.02] active:scale-[0.98] group relative overflow-hidden",
       selectedType === type.id 
         ? "border-blue-600 bg-blue-50/10 ring-4 ring-blue-50/30" 
         : "border-white bg-white hover:border-slate-100 shadow-sm shadow-slate-200/50"
     )}
   >

{step === 'type' && (
  <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
     <div className="space-y-2">
        <h1 className="text-3xl font-black text-slate-900 tracking-tight">1. Select a type of QR code</h1>
     </div>
     <div className="grid grid-cols-2 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {qrTypes.map(type => (
           <button
             key={type.id}
             onMouseEnter={() => setHoveredType(type.id)}
             onMouseLeave={() => setHoveredType(null)}
             onClick={() => setSelectedType(type.id)}
             className={cn(
               "flex flex-col items-center text-center p-6 rounded-[2rem] border-2 transition-all hover:scale-[1.02] active:scale-[0.98] group relative overflow-hidden",
               selectedType === type.id 
                 ? "border-blue-600 bg-blue-50/10 ring-4 ring-blue-50/30" 
                 : "border-white bg-white hover:border-slate-100 shadow-sm shadow-slate-200/50"
             )}
           >
              <div className={cn(
                "w-16 h-16 rounded-full flex items-center justify-center transition-all mb-4 border-2",
                selectedType === type.id 
                  ? "bg-blue-600 text-white border-blue-600 shadow-lg shadow-blue-200" 
                  : "bg-white text-slate-400 border-slate-100 group-hover:border-blue-100 group-hover:text-blue-600"
              )}>
                 <type.icon className="w-7 h-7" />
              </div>
              <div className="space-y-1">
                 <h3 className="font-black text-slate-900 text-sm tracking-tight">{type.title}</h3>
                 <p className="text-[10px] font-medium text-slate-400 leading-tight px-2">{type.description}</p>
              </div>
              {type.category === 'dynamic' && (
                 <div className="absolute top-3 right-3 w-1.5 h-1.5 bg-blue-500 rounded-full animate-pulse" />
              )}
           </button>
        ))}
     </div>
  </div>
)}

